arguments.command:
# Use nm or readelf to find the actual function symbol at those addresses
# The DWARF info maps to a label, but let's check the ELF symbol table
llvm-nm-18 --defined-only /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | awk '$1 != "" {print}' | sort | awk -v a1="2f4b20" -v a2="2f4c84" '
BEGIN { split("2f4b20 2f4c84", addrs) }
{
  addr = $1
  if (addr <= "00000000002f4b20") { prev1_addr=addr; prev1_name=$3 }
  if (addr <= "00000000002f4c84") { prev2_addr=addr; prev2_name=$3 }
}
END {
  print "0x2f4b20 is in: " prev1_name " (starts at 0x" prev1_addr ")"
  print "0x2f4c84 is in: " prev2_name " (starts at 0x" prev2_addr ")"
}' 2>&1 | head -10

# Alternative: use readelf
echo "---"
readelf -sW /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | grep -i "sgen\|worker\|cond_wait\|thread_wait" | grep -i "FUNC" | head -10

