{"command": "# Try looking at ALL func symbols (including LOCAL) 
readelf -sW /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | awk '
/FUNC/ {
  addr = strtonum("0x" $2)
  size = strtonum($3)
  if (size > 0 && addr <= 0x2f4b20 && addr + size > 0x2f4b20) print "0x2f4b20 -> " $8 " (start=0x" $2 ", size=" $3 ")"
  if (size > 0 && addr <= 0x2f4c84 && addr + size > 0x2f4c84) print "0x2f4c84 -> " $8 " (start=0x" $2 ", size=" $3 ")"
  if (size > 0 && addr <= 0x2c1a40 && addr + size > 0x2c1a40) print "0x2c1a40 -> " $8 " (start=0x" $2 ", size=" $3 ")"
}'", "description": "Find all function symbols at offsets", "initial_wait": 10}
